+    /// Parse CREATE statement (CREATE VECTOR INDEX)
+    fn parseCreateStatement(self: *Self) !Statement {
+        _ = try self.expect(.CREATE);
+
+        // Check for VECTOR INDEX
+        if (self.match(&[_]TokenType{.VECTOR})) {
